@module gridPane  src=gridPane.lua  loc=1156  sha=ec591ad  mode=chunk  self=gridPane
@deps cm, cmgr, chrome, gui, tv, inputAllowed, chordEntry

# Invariants & contracts
  @invariant  grid render + input only; tracker state lives in tv/ec, never cached here  @ 18
  @invariant  col.x == nil is the visibility predicate; per-column draws must gate on it  @ 19
  @invariant  cell coords 0-indexed; header rows at -HEADER, row-num gutter at -GUTTER  @ 20
  @invariant  page-persistent state: cellW/H, dragging, laneConsumed, paintLast  @ 21
  @contract  host supplies inputAllowed() -- folds modal/picker/item-active/palette/strip gates  @ 22
  @contract  host chordEntry=false gates the chord gesture off (the pattern editor passes false)  @ 23
  @contract  bails if laneConsumed; lane strip wins gestures over the tracker grid  @ 953
  @contract  right-click on channel-label row toggles mute  @ 954
  @contract  click on label rows selects channel/column  @ 955
  @contract  body click moves cursor and arms drag  @ 956
  @contract  no-op unless inputAllowed(); host folds modal/picker/item-active/palette/strip  @ 1096
  @contract  every fresh press enters; only lastEditKey autorepeats  @ 1097
  @contract  scans editKeys per frame; reads ec/grid fresh (editEvent may rebuild)  @ 1098
  @contract  a note key typed while armed exits region mode then enters (execute-through)  @ 1099
  @contract  Shift+notechar strikes chords (+Alt spreads channels); Shift+digit value place-walk  @ 1100
  @contract  Backspace deletes last chord note; Shift+=/- nudges vel; shift release commits  @ 1101

